/**
 * @summary Trending hashtag rooms
 */
export const getGetTrendingRoomsUrl = (params?: GetTrendingRoomsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/rooms/trending?${stringifiedParams}`
    : `/api/rooms/trending`;
};

export const getTrendingRooms = async (
  params?: GetTrendingRoomsParams,
  options?: RequestInit,
): Promise<Room[]> => {
  return customFetch<Room[]>(getGetTrendingRoomsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetTrendingRoomsQueryKey = (
  params?: GetTrendingRoomsParams,
) => {
  return [`/api/rooms/trending`, ...(params ? [params] : [])] as const;
};

export const getGetTrendingRoomsQueryOptions = <
  TData = Awaited<ReturnType<typeof getTrendingRooms>>,
  TError = ErrorType<unknown>,
>(
  params?: GetTrendingRoomsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTrendingRooms>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetTrendingRoomsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getTrendingRooms>>
  > = ({ signal }) => getTrendingRooms(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getTrendingRooms>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

